import clsx from 'clsx';
import type moment from 'moment';
import React from 'react';
import { Button } from '../../button';
import { useCssScope } from '../../config-provider/hooks';
import { Space } from '../../space';
import { isFunction } from '../../util';
import { useRangePickerContext } from '../RangePicker/Context';
import type { RangeValue } from '../interface';
import type { RangePickerFooterProps } from './types';

import '../style';

export const RangePickerFooter = (props: RangePickerFooterProps) => {
  const { renderExtraFooter, ranges } = props;
  const pickerFooterCssScope = useCssScope('picker__footer');
  const rangePickerCtx = useRangePickerContext();
  const { localMode, value, setValue, setOpened } = rangePickerCtx;
  const footerContent: React.ReactNode[] = [];

  const onQuickSelect = (selectedValue: RangeValue) => {
    setValue(selectedValue);
    setOpened(false);
  };

  if (renderExtraFooter) {
    footerContent.push(
      <div key="extra" className={pickerFooterCssScope('__extra')}>
        {renderExtraFooter(rangePickerCtx)}
      </div>,
    );
  } else if (localMode === 'date' && ranges) {
    footerContent.push(
      <div key="default" className={pickerFooterCssScope('__range')}>
        <Space size="small" wrap>
          {Object.entries(ranges).map(([btnText, rangeValueOrFunc]) => {
            let rangeValue: [moment.Moment, moment.Moment];
            if (isFunction(rangeValueOrFunc)) {
              rangeValue = rangeValueOrFunc();
            } else {
              rangeValue = rangeValueOrFunc;
            }
            const isSelected =
              value?.[0]?.toString() === rangeValue[0].toString() &&
              value?.[1]?.toString() === rangeValue[1].toString();
            return (
              <Button
                className={clsx(pickerFooterCssScope('__range__preset-btn'))}
                key={btnText}
                type="text"
                selected={isSelected}
                color="primary"
                onClick={() => onQuickSelect(rangeValue)}
              >
                {btnText}
              </Button>
            );
          })}
        </Space>
        <div style={{ flex: 1 }} />
      </div>,
    );
  }
  if (footerContent.length) {
    return <div className={pickerFooterCssScope()}>{footerContent}</div>;
  }
  return null;
};
